<section class="portal-page"><div class="portal-head"><div><span class="eyebrow">PATIENT PORTAL</span><h1>Notifications</h1><p>Appointment confirmations, changes and account updates.</p></div><form method="post" action="<?=url('notifications/read-all')?>"><?=csrf_field()?><button class="btn outline">Mark all as read</button></form></div><div class="notification-list"><?php foreach($notifications as$n):?><article class="<?=$n['read_at']?'':'unread'?>"><div><span><?=e(strtoupper($n['type']))?> • <?=date('d M Y, h:i A',strtotime($n['created_at']))?></span><h3><?=e($n['title'])?></h3><p><?=e($n['message'])?></p></div><?php if(!$n['read_at']):?><form method="post" action="<?=url('notification/read')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$n['id']?>"><input type="hidden" name="redirect" value="<?=e($n['action_url']?:'notifications')?>"><button class="btn small">Open</button></form><?php elseif($n['action_url']):?><a href="<?=url($n['action_url'])?>">View →</a><?php endif;?></article><?php endforeach;?><?php if(!$notifications):?><div class="empty">You have no notifications yet.</div><?php endif;?></div></section>
